export const meta = {
  name: 'qa-csp-search',
  description: 'Semantic search for CSP configuration in Nablarch web apps',
  phases: [
    { title: 'SemanticSearch', detail: 'Search knowledge files for CSP related content' },
    { title: 'ReadSections', detail: 'Read selected sections' },
    { title: 'GenerateAnswer', detail: 'Generate and verify answer' }
  ]
}

phase('SemanticSearch')

const searchResult = await agent(
  `Execute the semantic search workflow defined in workflows/semantic-search.md.

Working directory: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6

Query: "Content Security Policyを有効にしたい。NablarchのWeb画面でCSPを設定するにはどうすればいい？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

Read the file workflows/semantic-search.md and follow it exactly. The knowledge base is at knowledge/ directory relative to the working directory /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6.

For each page you consider, record WHY it was selected or skipped.
For each section, record WHY it was selected (high/partial) or skipped.

Return a JSON object with:
{
  "selected_sections": [
    {"file": "<full path>", "section_id": "<sN>", "relevance": "<high|partial>", "reason": "<why selected>"}
  ],
  "selected_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why selected>"}
  ],
  "excluded_pages": [
    {"path": "<page path relative to knowledge/>", "reason": "<why skipped>"}
  ],
  "excluded_sections": [
    {"file": "<full path>", "section_id": "<sN>", "reason": "<why skipped>"}
  ]
}`,
  {
    label: 'semantic-search',
    phase: 'SemanticSearch',
    schema: {
      type: 'object',
      properties: {
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_sections', 'selected_pages', 'excluded_pages', 'excluded_sections']
    }
  }
)

phase('ReadSections')

// Select sections: all high first, then partial, max 10
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')
log(`Reading ${sectionsToRead.length} sections: ${readArgs}`)

const sectionsContent = await agent(
  `Run this bash command and return the complete output as-is:
bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readArgs}

Return the raw text output from the command.`,
  { label: 'read-sections', phase: 'ReadSections' }
)

phase('GenerateAnswer')

const answer = await agent(
  `You are answering a question about Nablarch web framework in Japanese.

Question: "Content Security Policyを有効にしたい。NablarchのWeb画面でCSPを設定するにはどうすればいい？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

processing_type: ウェブアプリケーション
purpose: セキュリティ対応したい

Here are the knowledge sections:
${sectionsContent}

Generate a Japanese answer following this format:

**結論**: Direct answer (1-2 sentences, include specific method/class names)

**根拠**: Code/config examples that back the conclusion (use code blocks, quote verbatim from sections)

**注意点**: Constraints, common mistakes (omit if nothing applies)

参照: Only sections actually cited (file.json:sN format, omit category path)

Stay within 500 tokens (up to 800 for complex questions).

Then verify the answer: check all Nablarch-specific claims (API names, class names, config methods, behavior specs, constraints, parameters) are directly supported by the sections content. Do NOT flag general Java/programming knowledge.

Return JSON:
{
  "answer_text": "<the answer in Japanese markdown>",
  "verify_result": "PASS" or "FAIL",
  "issues": ["<unsupported claim>"] or [],
  "used_sections": [{"ref": "<file.json:sN>", "reason": "<why used>"}],
  "unused_sections": [{"ref": "<file.json:sN>", "reason": "<why not used>"}]
}`,
  {
    label: 'generate-answer',
    phase: 'GenerateAnswer',
    schema: {
      type: 'object',
      properties: {
        answer_text: { type: 'string' },
        verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
        issues: { type: 'array', items: { type: 'string' } },
        used_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        },
        unused_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              ref: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['ref', 'reason']
          }
        }
      },
      required: ['answer_text', 'verify_result', 'issues', 'used_sections', 'unused_sections']
    }
  }
)

let finalAnswer = answer.answer_text
if (answer.verify_result === 'FAIL') {
  const revisedAnswer = await agent(
    `Revise this Japanese answer about Nablarch. Remove or correct these unsupported claims: ${JSON.stringify(answer.issues)}

Original answer:
${answer.answer_text}

Knowledge sections:
${sectionsContent}

Return only the revised answer text in Japanese markdown (same format: 結論/根拠/注意点/参照).`,
    { label: 'revise-answer', phase: 'GenerateAnswer' }
  )
  finalAnswer = revisedAnswer
}

return {
  searchResult,
  sectionsToRead,
  answer,
  finalAnswer
}

